# Combinatorially identify subsets of a molecule.
# Start with an isotopically labelled molecule. In this case the
# molecules are generated by `tsubstructure -j 1 -j sequential` with a
# query that specified a pair of bonded atoms.
# In that way, bonds are annotated with isotopes, 1-2, 3-4, 5-6.
# The query was set up so the odd numbered isotopes are all in a
# common core, and all the even numbered isotopes are in sidechians.
# run with
# ${LILLYMOL_HOME}/run_python.sh ${LILLYMOL_HOME}/contrib/bin/sidechain_subsets.py ...
# Output is to stdout.
# The --maxbonds option is important. The default is 1, but if that is increased
# and the molecules are large, you may run into combinatorial problems.
# For example, starting with 1.2k likely cyclic peptides from Chembl, running
# with --maxbonds 3 generated 16k molecules - took about 5 seconds.

from itertools import combinations
from collections import Counter

from absl import app
from absl import flags
from absl import logging

FLAGS = flags.FLAGS
flags.DEFINE_integer('maxbonds', 1, "Max number of fragments to be reattached")

from lillymol import *
from lillymol_io import *

class Stats:
  def __init__(self):
    self.molecules_read = 0
    self.molecules_with_isotopes = 0
    self.bonds_broken = Counter()
    self.molecules_written = 0

  def report(self):
    logging.info("Molecules read %d", self.molecules_read)
    logging.info("Molecules with isotopes %d", self.molecules_with_isotopes)
    logging.info("Molecules written %d", self.molecules_written)

    logging.info("Broken bond count distribution")
    for nbonds, count in sorted(self.bonds_broken.items()):
      logging.info("  %d molecules had %d bonds", count, nbonds)

def remove_isotope_pair_bonds(mol):
    """Remove odd/even isotope-pair bonds.

    Returns:
      dict mapping isotope -> atom number.
    """
    isotope_to_atom = {}

    for i in range(mol.natoms()):
        iso = mol.isotope(i)
        if iso > 0:
            isotope_to_atom[iso] = i

    for odd_iso, a1 in isotope_to_atom.items():
        if odd_iso % 2 == 0:
            continue

        a2 = isotope_to_atom.get(odd_iso + 1)
        if a2 is None:
            continue

        if mol.are_bonded(a1, a2):
            mol.remove_bond_between_atoms(a1, a2)
        else:
          logging.warning("Matched atoms not bonded %d %d in %s", a1, a2, mol.name())

    return isotope_to_atom


def atom_pairs_from_isotopes(isotope_to_atom):
    """Return atom pairs corresponding to odd/even isotope labels."""
    result = []

    for iso in sorted(isotope_to_atom):
        if iso % 2 == 0:
            continue

        even_iso = iso + 1
        if even_iso not in isotope_to_atom:
            continue

        result.append((isotope_to_atom[iso], isotope_to_atom[even_iso]))

    return result


def generate_products(m, maxbonds):
    """Given pairs of bonded atoms marked by consecutive odd/even pairs of
      isotopic labels, remove all those bonds, and generate all pairwise
      products that re-attach as many as `maxbonds` fragments.
    Note that `m` is left in an indeterminate state upon completion.
    """
    isotope_to_atom = remove_isotope_pair_bonds(m)
    if len(isotope_to_atom) == 0:
      logging.warning("No isotopes in %s", m.name())
      return 0, 0

    atom_pairs = atom_pairs_from_isotopes(isotope_to_atom)
    nbonds = len(atom_pairs)

    maxbonds = min(maxbonds, nbonds)
    molecules_written = 0

    for nchoose in range(1, maxbonds + 1):
        for subset in combinations(atom_pairs, nchoose):
            mcopy = Molecule(m)

            for a1, a2 in subset:
                mcopy.add_bond(a1, a2, SINGLE_BOND)
                mcopy.unset_all_implicit_hydrogen_information(a1)
                mcopy.unset_all_implicit_hydrogen_information(a2)

            mcopy.reduce_to_largest_fragment()

            if not mcopy.valence_ok():
              logging.warning("Valence error in %s", mcopy.smiles())
              continue

            print(f"{mcopy.unique_smiles()} {m.name()}")
            molecules_written += 1

    return nbonds, molecules_written

def sidechain_subsets_do(mol, maxbonds, stats):
  stats.molecules_read += 1

  nbonds, molecules_written = generate_products(mol, maxbonds)

  if nbonds > 0:
    stats.molecules_with_isotopes += 1
    stats.bonds_broken[nbonds] += 1

  stats.molecules_written += molecules_written


def sidechain_subsets(argv):
  if len(argv) == 1:
    logging.error("Must specify input file")
    return 1

  stats = Stats()

  with ReaderContext(argv[1]) as reader:
    for mol in reader:
      sidechain_subsets_do(mol, FLAGS.maxbonds, stats)

  stats.report()
  return 0

if __name__ == '__main__':
  app.run(sidechain_subsets)
